const config = $input.first().json;
const format = (date) => date.toISOString().slice(0, 10).replaceAll('-', '') + '00';
const end = new Date(); end.setUTCDate(end.getUTCDate() - 1);
const start = new Date(end); start.setUTCDate(start.getUTCDate() - 29);
return [{ json: { ...config, start: format(start), end: format(end), encodedTitle: encodeURIComponent(config.articleTitle.replaceAll(' ', '_')) } }];

const config = $('Build 30 day pageview request').first().json;
const items = $input.first().json.items || [];
if (items.length < 14) return [];
const views = items.map((item) => Number(item.views || 0));
const average = (values) => values.reduce((sum, value) => sum + value, 0) / values.length;
const recent = average(views.slice(-7)); const previous = average(views.slice(-14, -7));
const change = previous ? ((recent - previous) / previous) * 100 : 0;
return [{ json: { workspaceId: config.workspaceId, title: `Wikimedia attention: ${config.articleTitle}`, sourceUrl: `https://${config.project}/wiki/${encodeURIComponent(config.articleTitle.replaceAll(' ', '_'))}`, publishedAt: new Date().toISOString(), sourceName: 'Wikimedia Pageviews API', sourceType: 'report', content: `Wikimedia pageview attention proxy for ${config.articleTitle}. Recent 7-day average: ${recent.toFixed(0)} daily views. Previous 7-day average: ${previous.toFixed(0)}. Change: ${change.toFixed(1)}%. This measures information-seeking attention, not demand, sales, or purchase intent.` } }];
